package com.example.education.system.ai.config;import org.springframework.boot.context.properties.ConfigurationProperties;import org.springframework.context.annotation.Configuration;import java.time.Duration;/** * AI 对话相关配置项。 */@Configuration@ConfigurationProperties(prefix = "ai.chat")public class AiChatProperties {    private boolean summaryEnabled = false;    private int summaryBatchSize = 20;    private Duration sessionTtl = Duration.ofDays(7);    private int maxHistoryMessages = 20;    public boolean isSummaryEnabled() {        return summaryEnabled;    }    public void setSummaryEnabled(boolean summaryEnabled) {        this.summaryEnabled = summaryEnabled;    }    public int getSummaryBatchSize() {        return summaryBatchSize;    }    public void setSummaryBatchSize(int summaryBatchSize) {        this.summaryBatchSize = summaryBatchSize;    }    public Duration getSessionTtl() {        return sessionTtl;    }    public void setSessionTtl(Duration sessionTtl) {        this.sessionTtl = sessionTtl;    }    public int getMaxHistoryMessages() {        return maxHistoryMessages;    }    public void setMaxHistoryMessages(int maxHistoryMessages) {        this.maxHistoryMessages = maxHistoryMessages;    }    /** 便于 YAML 配置：ai.chat.session-ttl-days: 7 */    public void setSessionTtlDays(long days) {        this.sessionTtl = Duration.ofDays(days);    }}